{"content": "import crypto from 'crypto';
import { readFileSync } from 'fs';

const SECRET = readFileSync('.secret', 'utf-8').trim();

export function login(username: string, password: string): string | null {
  const users = JSON.parse(readFileSync('users.json', 'utf-8'));
  const user = users.find((u: any) => u.username === username);
  if (!user) return null;
  const hash = crypto.createHash('sha256').update(password + user.salt).digest('hex');
  if (hash !== user.passwordHash) return null;
  const token = crypto.randomBytes(32).toString('hex');
  const tokens = JSON.parse(readFileSync('tokens.json', 'utf-8'));
  tokens[token] = { userId: user.id, created: Date.now() };
  require('fs').writeFileSync('tokens.json', JSON.stringify(tokens));
  return token;
}

export function validateToken(token: string): any {
  const tokens = JSON.parse(readFileSync('tokens.json', 'utf-8'));
  return tokens[token] || null;
}

export function logout(token: string): void {
  const tokens = JSON.parse(readFileSync('tokens.json', 'utf-8'));
  delete tokens[token];
  require('fs').writeFileSync('tokens.json', JSON.stringify(tokens));
}
"}

