No error handler registered. Here's my approach — instead of wrapping every route in try/catch (repetitive), I'll add:

1. An async wrapper utility
2. A centralized error handler middleware
3. A custom error class for HTTP errors

```tool_call
{"name": "write_file", "arguments": {"path": "src/middleware/errorHandler.ts", "content": "import { Request, Response, NextFunction } from 'express';

/** Custom error with HTTP status code */
export class HttpError extends Error {
  constructor(public statusCode: number, message: string) {
    super(message);
  }
}

/** Wrap async route handlers so thrown errors reach the error handler */
export function asyncHandler(fn: (req: Request, res: Response, next: NextFunction) => Promise<any>) {
  return (req: Request, res: Response, next: NextFunction) => {
    fn(req, res, next).catch(next);
  };
}

/** Central error handler — register last with app.use() */
export function errorHandler(err: Error, _req: Request, res: Response, _next: NextFunction) {
  console.error(err.stack);

  if (err instanceof HttpError) {
    return res.status(err.statusCode).json({ error: err.message });
  }

  // Don't leak internal error details in production
  const message = process.env.NODE_ENV === 'production'
    ? 'Internal server error'
    : err.message;

  res.status(500).json({ error: message });
}
"}}
```

