import { Server } from 'http';

let wss: WebSocketServer;

// Map of userId -> Set of WebSocket connections
const clients = new Map<string, Set<WebSocket>>();

export function setupWebSocket(server: Server): void {
  wss = new WebSocketServer({ server, path: '/ws' });

  wss.on('connection', (ws, req) => {
    // Expect userId as query param: /ws?userId=xxx
    const url = new URL(req.url || '', `http://${req.headers.host}`);
    const userId = url.searchParams.get('userId');

    if (!userId) {
      ws.close(4001, 'userId required');
      return;
    }

    // Register this connection
    if (!clients.has(userId)) clients.set(userId, new Set());
    clients.get(userId)!.add(ws);

    ws.on('close', () => {
      clients.get(userId)?.delete(ws);
      if (clients.get(userId)?.size === 0) clients.delete(userId);
    });

    ws.send(JSON.stringify({ type: 'connected', userId }));
  });
}

/** Send a notification to a specific user (all their connected clients) */
export function notifyUser(userId: string, payload: Record<string, unknown>): void {
  const sockets = clients.get(userId);
  if (!sockets) return;

  const message = JSON.stringify(payload);
  for (const ws of sockets) {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message);
    }
  }
}

/** Broadcast to all connected clients */
export function broadcast(payload: Record<string, unknown>): void {
  if (!wss) return;
  const message = JSON.stringify(payload);
  for (const client of wss.clients) {
    if (client.readyState === WebSocket.OPEN) {
      client.send(message);
    }
  }
}
"}}
