The pool has no error handling, no retry logic, and no connection validation. If the database restarts, the pool will hold dead connections and queries will fail.

Here's what I'll add:
1. Connection pool configuration (timeouts, max connections)
2. Error event handler (log and recover from idle client errors)
3. Startup health check
4. Query retry wrapper for transient failures

```tool_call
{"name": "write_file", "arguments": {"path": "src/database.ts", "content": "import { Pool, PoolConfig } from 'pg';

const config: PoolConfig = {
  connectionString: process.env.DATABASE_URL,
  max: 20,                         // max pool size
  idleTimeoutMillis: 30_000,       // close idle connections after 30s
  connectionTimeoutMillis: 5_000,  // fail if can't connect in 5s
};

export const pool = new Pool(config);

// Handle unexpected errors on idle clients to prevent crashes
pool.on('error', (err) => {
  console.error('Unexpected database pool error:', err.message);
});

// Verify connection on startup
pool.query('SELECT 1')
  .then(() => console.log('Database connected'))
  .catch((err) => {
    console.error('Database connection failed:', err.message);
    console.error('The app will attempt to reconnect on the next query.');
  });

/**
 * Execute a query with automatic retry for transient errors.
 * Retries once after 500ms for connection-related failures.
 */
export async function queryWithRetry<T = any>(
  sql: string,
  params?: any[],
  retries = 1,
): Promise<{ rows: T[]; rowCount: number | null }> {
  try {
    return await pool.query(sql, params);
  } catch (err: any) {
    const isTransient =
      err.code === 'ECONNREFUSED' ||
      err.code === '57P01' || // admin_shutdown
      err.code === '57P03' || // cannot_connect_now
      err.code === '08006' || // connection_failure
      err.code === '08003';   // connection_does_not_exist

    if (isTransient && retries > 0) {
      await new Promise((r) => setTimeout(r, 500));
      return queryWithRetry(sql, params, retries - 1);
    }
    throw err;
  }
}
"}}
