{"name":"write_file","arguments":{"path":"src/queue/worker.ts","content":"import { pool } from '../database';

type Handler = (payload: Record<string, unknown>) => Promise<void>;
const handlers = new Map<string, Handler>();

export function registerHandler(type: string, fn: Handler) {
  handlers.set(type, fn);
}

export async function enqueue(type: string, payload: object, runAt?: Date) {
  await pool.query(
    'INSERT INTO jobs(type, payload, run_at) VALUES($1, $2, $3)',
    [type, JSON.stringify(payload), runAt ?? new Date()]
  );
}

export async function processNext(): Promise<boolean> {
  const result = await pool.query(`
    UPDATE jobs SET status = 'processing', attempts = attempts + 1
    WHERE id = (
      SELECT id FROM jobs
      WHERE status = 'pending' AND run_at <= NOW()
      ORDER BY run_at
      FOR UPDATE SKIP LOCKED
      LIMIT 1
    )
    RETURNING *
  `);

  const job = result.rows[0];
  if (!job) return false;

  const handler = handlers.get(job.type);
  if (!handler) {
    await pool.query("UPDATE jobs SET status = 'failed', last_error = $1 WHERE id = $2", ['No handler registered', job.id]);
    return true;
  }

  try {
    await handler(job.payload);
    await pool.query("UPDATE jobs SET status = 'done' WHERE id = $1", [job.id]);
  } catch (err: any) {
    const status = job.attempts >= job.max_attempts ? 'failed' : 'pending';
    const runAt = new Date(Date.now() + job.attempts * 60_000); // exponential backoff
    await pool.query(
      'UPDATE jobs SET status = $1, last_error = $2, run_at = $3 WHERE id = $4',
      [status, err.message, runAt, job.id]
    );
  }

  return true;
}

export function startWorker(intervalMs = 5000) {
  return setInterval(async () => {
    let processed = true;
    while (processed) processed = await processNext();
  }, intervalMs);
}
"}}
```

Queue implemented. To send emails:

```typescript
registerHandler('send-email', async (payload) => {
  await mailer.send(payload.to, payload.subject, payload.body);
});

// Enqueue a job
await enqueue('send-email', { to: 'user@example.com', subject: 'Welcome!', body: '...' });

// Start the worker (call once at startup)
startWorker();
```

`FOR UPDATE SKIP LOCKED` in the query is key — it lets multiple worker processes claim jobs without collisions or deadlocks. Failed jobs retry up to 3 times with increasing delays.

