{"name":"write_file","arguments":{"path":"src/notifications.ts","content":"import { WebSocketServer, WebSocket } from 'ws';
import type { Server } from 'http';

const clients = new Map<string, Set<WebSocket>>();

export function setupWebSockets(server: Server) {
  const wss = new WebSocketServer({ server, path: '/ws' });

  wss.on('connection', (ws, req) => {
    const userId = req.url?.split('userId=')[1]; // e.g. /ws?userId=123
    if (!userId) { ws.close(1008, 'userId required'); return; }

    if (!clients.has(userId)) clients.set(userId, new Set());
    clients.get(userId)!.add(ws);

    ws.on('close', () => {
      clients.get(userId)?.delete(ws);
      if (clients.get(userId)?.size === 0) clients.delete(userId);
    });
  });

  return wss;
}

export function notify(userId: string, event: object) {
  const userClients = clients.get(userId);
  if (!userClients) return;
  const payload = JSON.stringify(event);
  for (const ws of userClients) {
    if (ws.readyState === WebSocket.OPEN) ws.send(payload);
  }
}
