I'll implement the Command pattern — each operation is an object that knows how to do and undo itself. The undo/redo history is two stacks: undo stack and redo stack.

```tool_call
{"name":"write_file","arguments":{"path":"src/editor.ts","content":"interface EditorCommand {
  execute(): void;
  undo(): void;
}

export class Editor {
  private content = '';
  private undoStack: EditorCommand[] = [];
  private redoStack: EditorCommand[] = [];

  private run(cmd: EditorCommand) {
    cmd.execute();
    this.undoStack.push(cmd);
    this.redoStack = []; // New action clears redo history
  }

  insert(pos: number, text: string) {
    this.run({
      execute: () => {
        this.content = this.content.slice(0, pos) + text + this.content.slice(pos);
      },
      undo: () => {
        this.content = this.content.slice(0, pos) + this.content.slice(pos + text.length);
      },
    });
  }

  delete(pos: number, length: number) {
    const deleted = this.content.slice(pos, pos + length);
    this.run({
      execute: () => {
        this.content = this.content.slice(0, pos) + this.content.slice(pos + length);
      },
      undo: () => {
        this.content = this.content.slice(0, pos) + deleted + this.content.slice(pos);
      },
    });
  }

  undo() {
    const cmd = this.undoStack.pop();
    if (!cmd) return;
    cmd.undo();
    this.redoStack.push(cmd);
  }

  redo() {
    const cmd = this.redoStack.pop();
    if (!cmd) return;
    cmd.execute();
    this.undoStack.push(cmd);
  }

  canUndo() { return this.undoStack.length > 0; }
  canRedo() { return this.redoStack.length > 0; }
  getContent() { return this.content; }
}
"}}
