I'll add exponential backoff with jitter — retrying immediately would hammer a struggling server. Jitter (random delay variation) prevents all clients from retrying in sync.

```tool_call
{"name":"write_file","arguments":{"path":"src/apiClient.ts","content":"const DEFAULT_RETRIES = 3;
const BASE_DELAY_MS = 300;

function isRetryable(status: number): boolean {
  // Retry on server errors and rate limiting, not on client errors
  return status === 429 || (status >= 500 && status < 600);
}

async function sleep(ms: number) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

export async function apiRequest(
  url: string,
  options?: RequestInit,
  retries = DEFAULT_RETRIES
): Promise<any> {
  let lastError: Error | null = null;

  for (let attempt = 0; attempt <= retries; attempt++) {
    if (attempt > 0) {
      // Exponential backoff with ±20% jitter
      const base = BASE_DELAY_MS * Math.pow(2, attempt - 1);
      const jitter = base * 0.2 * (Math.random() * 2 - 1);
      await sleep(base + jitter);
    }

    const res = await fetch(url, options);

    if (res.ok) return res.json();

    if (!isRetryable(res.status)) {
      throw new Error(`HTTP ${res.status}: ${await res.text()}`);
    }

    lastError = new Error(`HTTP ${res.status}`);
  }

  throw lastError;
}
"}}
