No TTL, no max size — the cache grows forever and never evicts anything. That's your memory leak. Two fixes needed:

1. Add TTL-based expiry
2. Add a max size with LRU eviction

```tool_call
{"name":"write_file","arguments":{"path":"src/cache.ts","content":"const MAX_SIZE = 1000;
const DEFAULT_TTL = 5 * 60 * 1000; // 5 minutes

interface Entry {
  value: unknown;
  expiresAt: number;
}

const store = new Map<string, Entry>();

function evictExpired() {
  const now = Date.now();
  for (const [key, entry] of store) {
    if (now > entry.expiresAt) store.delete(key);
  }
}

export function cacheGet<T>(key: string): T | null {
  const entry = store.get(key);
  if (!entry) return null;
  if (Date.now() > entry.expiresAt) { store.delete(key); return null; }
  return entry.value as T;
}

export function cacheSet(key: string, value: unknown, ttlMs = DEFAULT_TTL) {
  evictExpired();
  if (store.size >= MAX_SIZE) {
    // Evict oldest entry
    store.delete(store.keys().next().value);
  }
  store.set(key, { value, expiresAt: Date.now() + ttlMs });
}

export function cacheDelete(key: string) { store.delete(key); }
export function cacheSize() { return store.size; }
"}}
