  response    JSONB       NOT NULL,
  status_code INTEGER     NOT NULL,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Expire old keys after 24 hours
CREATE INDEX idx_idempotency_keys_created ON idempotency_keys(created_at);
"}}
