```tool_call
{"name":"write_file","arguments":{"path":"src/middleware/idempotency.ts","content":"import { Request, Response, NextFunction } from 'express';
import { pool } from '../database';

export async function idempotencyMiddleware(req: Request, res: Response, next: NextFunction) {
  const key = req.headers['idempotency-key'] as string;
  if (!key) return next(); // Key optional — only enforced by payment route

  // Check if we've seen this key before
  const existing = await pool.query(
    'SELECT response, status_code FROM idempotency_keys WHERE key = $1',
    [key]
  );

  if (existing.rows[0]) {
    // Replay the stored response
    return res
      .status(existing.rows[0].status_code)
      .json(existing.rows[0].response);
  }

  // Capture the response before sending
  const originalJson = res.json.bind(res);
  res.json = function (body) {
    if (res.statusCode < 500) {
      pool.query(
        'INSERT INTO idempotency_keys(key, response, status_code) VALUES($1, $2, $3) ON CONFLICT DO NOTHING',
        [key, JSON.stringify(body), res.statusCode]
      );
    }
    return originalJson(body);
  };

  next();
}
"}}
