No existing event system. I'll build a typed pub/sub over Node's built-in `EventEmitter` so event names and payloads are compile-time checked.

```tool_call
{"name":"write_file","arguments":{"path":"src/lib/events.ts","content":"import { EventEmitter } from 'events';

// Define all events and their payload types here
export interface AppEvents {
  'user.created': { userId: string; email: string };
  'user.deleted': { userId: string };
  'order.placed': { orderId: string; userId: string; total: number };
  'order.cancelled': { orderId: string; reason: string };
}

type EventName = keyof AppEvents;
type EventPayload<E extends EventName> = AppEvents[E];

class TypedEventBus {
  private emitter = new EventEmitter();

  on<E extends EventName>(event: E, handler: (payload: EventPayload<E>) => void) {
    this.emitter.on(event, handler);
    return () => this.emitter.off(event, handler); // returns unsubscribe fn
  }

  once<E extends EventName>(event: E, handler: (payload: EventPayload<E>) => void) {
    this.emitter.once(event, handler);
  }

  emit<E extends EventName>(event: E, payload: EventPayload<E>) {
    this.emitter.emit(event, payload);
  }
}

export const bus = new TypedEventBus();
"}}
```

