{"name":"write_file","arguments":{"path":"src/utils/transform.ts","content":"interface Item {
  category?: string;
  value?: number;
  [key: string]: unknown;
}

interface GroupedItems {
  items: Item[];
  total: number;
}

const DEFAULT_CATEGORY = 'uncategorized';

export function groupByCategory(items: Item[]): Record<string, GroupedItems> {
  return items.reduce<Record<string, GroupedItems>>((groups, item) => {
    const category = item.category ?? DEFAULT_CATEGORY;

    if (!groups[category]) {
      groups[category] = { items: [], total: 0 };
    }

    groups[category].items.push(item);
    groups[category].total += item.value ?? 0;

    return groups;
  }, {});
}
"}}
