React app. I'll create a `useFormSubmit` hook that prevents double-submission and shows loading state.

```tool_call
{"name":"write_file","arguments":{"path":"src/hooks/useFormSubmit.ts","content":"import { useState, useCallback } from 'react';

interface UseFormSubmitOptions {
  onSuccess?: (data: unknown) => void;
  onError?: (error: Error) => void;
}

export function useFormSubmit<T>(
  submitFn: (data: T) => Promise<unknown>,
  options: UseFormSubmitOptions = {}
) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const handleSubmit = useCallback(async (data: T) => {
    if (isSubmitting) return; // Prevent double-submission

    setIsSubmitting(true);
    setError(null);

    try {
      const result = await submitFn(data);
      options.onSuccess?.(result);
    } catch (err) {
      const error = err instanceof Error ? err : new Error(String(err));
      setError(error);
      options.onError?.(error);
    } finally {
      setIsSubmitting(false);
    }
  }, [isSubmitting, submitFn, options]);

  return { handleSubmit, isSubmitting, error };
}
"}}
```

Hook ready. Usage:

```tsx
const { handleSubmit, isSubmitting, error } = useFormSubmit(
  async (data) => {
    await api.post('/orders', data);
  },
  { onSuccess: () => router.push('/confirmation') }
);

<button onClick={() => handleSubmit(formData)} disabled={isSubmitting}>
  {isSubmitting ? 'Submitting...' : 'Place Order'}
</button>
{error && <p className="error">{error.message}</p>}
```

The guard `if (isSubmitting) return` in the hook prevents double-submission even if the button re-enables before the request completes. For extra safety on critical forms, combine with server-side idempotency keys.

