I'll add a plugin API where plugins can register new commands. Plugins are loaded from a config directory.

```tool_call
{"name":"write_file","arguments":{"path":"src/plugin.ts","content":"import fs from 'fs';
import path from 'path';
import os from 'os';

type CommandHandler = (args: string[]) => Promise<void>;

interface Plugin {
  name: string;
  version: string;
  commands: Record<string, CommandHandler>;
}

const registeredCommands = new Map<string, CommandHandler>();

export function registerPlugin(plugin: Plugin) {
  for (const [name, handler] of Object.entries(plugin.commands)) {
    if (registeredCommands.has(name)) {
      console.warn(`Plugin '${plugin.name}' tried to register duplicate command: ${name}`);
      continue;
    }
    registeredCommands.set(name, handler);
  }
  console.log(`Loaded plugin: ${plugin.name} v${plugin.version}`);
}

export function getCommand(name: string): CommandHandler | undefined {
  return registeredCommands.get(name);
}

export function listPluginCommands(): string[] {
  return [...registeredCommands.keys()];
}

export async function loadPlugins() {
  const pluginDir = path.join(os.homedir(), '.mytool', 'plugins');
  if (!fs.existsSync(pluginDir)) return;

  for (const file of fs.readdirSync(pluginDir)) {
    if (!file.endsWith('.js')) continue;
    try {
      const plugin = require(path.join(pluginDir, file));
      if (plugin.default) registerPlugin(plugin.default);
    } catch (err: any) {
      console.error(`Failed to load plugin ${file}: ${err.message}`);
    }
  }
}
"}}
