// Known bad user-agent substrings
const BAD_UA_PATTERNS = [
  'python-requests', 'scrapy', 'go-http-client', 'java/', 'libwww',
  'masscan', 'nikto', 'sqlmap', 'nmap',
];

// IPs to block (add from your logs)
const BLOCKED_IPS = new Set([
  '192.168.10.45', '10.0.0.88', '203.0.113.22', '198.51.100.5',
]);

export function botProtectionMiddleware(req: Request, res: Response, next: NextFunction) {
  const ip = req.ip ?? '';
  const ua = (req.headers['user-agent'] ?? '').toLowerCase();

  if (BLOCKED_IPS.has(ip)) {
    return res.status(429).json({ error: 'Too many requests' }); // Don't reveal it's a block
  }

  if (!req.headers['user-agent']) {
    return res.status(400).json({ error: 'Bad request' });
  }

  if (BAD_UA_PATTERNS.some(pattern => ua.includes(pattern))) {
    return res.status(403).json({ error: 'Forbidden' });
  }

  next();
}
