```tool_call
{"name":"write_file","arguments":{"path":"src/hooks/useDebounce.ts","content":"import { useState, useEffect } from 'react';

export function useDebounce<T>(value: T, delayMs = 300): T {
  const [debounced, setDebounced] = useState<T>(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delayMs);
    return () => clearTimeout(timer); // Clear on next keystroke
  }, [value, delayMs]);

  return debounced;
}
"}}
