{"name":"write_file","arguments":{"path":"src/components/SearchInput.tsx","content":"import React, { useState, useEffect } from 'react';
import { useDebounce } from '../hooks/useDebounce';

interface Props {
  onSearch: (query: string) => void;
  placeholder?: string;
  debounceMs?: number;
}

export function SearchInput({ onSearch, placeholder = 'Search...', debounceMs = 300 }: Props) {
  const [value, setValue] = useState('');
  const debounced = useDebounce(value, debounceMs);

  useEffect(() => {
    onSearch(debounced);
  }, [debounced, onSearch]);

  return (
    <input
      type="search"
      value={value}
      onChange={(e) => setValue(e.target.value)}
      placeholder={placeholder}
      aria-label={placeholder}
    />
  );
}
