Two services making external HTTP calls. Rather than duplicating retry logic, I'll write a generic `withRetry` wrapper.

```tool_call
{"name":"write_file","arguments":{"path":"src/lib/retry.ts","content":"export interface RetryOptions {
  maxAttempts?: number;
  baseDelayMs?: number;
  shouldRetry?: (error: unknown) => boolean;
}

function isNetworkError(err: unknown): boolean {
  if (!(err instanceof Error)) return false;
  return (
    err.message.includes('ECONNRESET') ||
    err.message.includes('ETIMEDOUT') ||
    err.message.includes('ENOTFOUND') ||
    err.message.includes('fetch failed') ||
    (err as any).code === 'ECONNREFUSED'
  );
}

export async function withRetry<T>(
  fn: () => Promise<T>,
  options: RetryOptions = {}
): Promise<T> {
  const { maxAttempts = 3, baseDelayMs = 500, shouldRetry = isNetworkError } = options;

  let lastError: unknown;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;

      if (attempt === maxAttempts || !shouldRetry(err)) throw err;

      const delay = baseDelayMs * Math.pow(2, attempt - 1);
      const jitter = Math.random() * delay * 0.2;
      await new Promise(r => setTimeout(r, delay + jitter));

      console.warn(`Attempt ${attempt} failed, retrying in ${Math.round(delay)}ms...`);
    }
  }

  throw lastError;
}
"}}
